// generateInstallCLISteps generates YAML steps to install or build the gh-aw CLI.
// In dev mode: builds from source using Setup Go + Build gh-aw (./gh-aw binary available)
// In release mode: installs the released CLI via the setup-cli action (gh aw available)
// In action mode: installs the released CLI via the gh-aw-actions/setup-cli action (gh aw available)
func generateInstallCLISteps(actionMode ActionMode, version string, actionTag string) string {
	if actionMode == ActionModeDev {
		return `      - name: Setup Go
        uses: ` + GetActionPin("actions/setup-go") + `
        with:
          go-version-file: go.mod
          cache: true

      - name: Build gh-aw
        run: make build

`
	}

	cliTag := actionTag
	if cliTag == "" {
		cliTag = version
	}

	// Action mode: use setup-cli action from external gh-aw-actions repository
	if actionMode == ActionModeAction {
		return `      - name: Install gh-aw
        uses: github/gh-aw-actions/setup-cli@` + cliTag + `
        with:
          version: ` + cliTag + `

`
	}

	// Release mode: use setup-cli action (consistent with copilot-setup-steps.yml)
	return `      - name: Install gh-aw
        uses: github/gh-aw/actions/setup-cli@` + cliTag + `
        with:
          version: ` + cliTag + `

`
}

action.new_str:
// generateInstallCLISteps generates YAML steps to install or build the gh-aw CLI.
// In dev mode: builds from source using Setup Go + Build gh-aw (./gh-aw binary available)
// In release mode: installs the released CLI via the setup-cli action (gh aw available)
// In action mode: installs the released CLI via the gh-aw-actions/setup-cli action (gh aw available)
func generateInstallCLISteps(actionMode ActionMode, version string, actionTag string, resolvers ...ActionSHAResolver) string {
	if actionMode == ActionModeDev {
		return `      - name: Setup Go
        uses: ` + GetActionPin("actions/setup-go") + `
        with:
          go-version-file: go.mod
          cache: true

      - name: Build gh-aw
        run: make build

`
	}

	cliTag := actionTag
	if cliTag == "" {
		cliTag = version
	}

	actionRepo := "github/gh-aw/actions/setup-cli"
	if actionMode == ActionModeAction {
		actionRepo = "github/gh-aw-actions/setup-cli"
	}
	actionRef := actionRepo + "@" + cliTag
	if len(resolvers) > 0 && resolvers[0] != nil && cliTag != "" {
		if sha, err := resolvers[0].ResolveSHA(actionRepo, cliTag); err == nil && sha != "" {
			actionRef = formatActionReference(actionRepo, sha, cliTag)
		} else if err != nil {
			maintenanceLog.Printf("Failed to resolve SHA for %s@%s: %v, falling back to version tag", actionRepo, cliTag, err)
		}
	}

	return `      - name: Install gh-aw
        uses: ` + actionRef + `
        with:
          version: ` + cliTag + `

`
}

