        }

        actionRepo := "github/gh-aw/actions/setup-cli"
        if actionMode == ActionModeAction {
                actionRepo = "github/gh-aw-actions/setup-cli"
        }
        actionRef := actionRepo + "@" + cliTag
        if len(resolvers) > 0 && resolvers[0] != nil && cliTag != "" {
                if sha, err := resolvers[0].ResolveSHA(actionRepo, cliTag); err == nil && sha != "" {
                        actionRef = formatActionReference(actionRepo, sha, cliTag)
                } else if err != nil {
                        maintenanceLog.Printf("Failed to resolve SHA for %s@%s: %v, falling back to version tag", actionRepo, cliTag, err)
                }
        }

        return `      - name: Install gh-aw
        uses: ` + actionRef + `
        with:
          version: ` + cliTag + `

`
}

