package main

import (
    "fmt"
    "os"
    "path/filepath"
    "regexp"
    "strings"

    "github.com/github/gh-aw/pkg/workflow"
)

const (
    version     = "v0.64.0"
    setupSHA    = "aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa"
    setupCliSHA = "51c65948c64ab6752536ead71fba1fc2c20ed0bc"
)

func generate(mode workflow.ActionMode, actionTag string, resolver *workflow.ActionResolver) string {
    out, err := os.MkdirTemp("", "gh-aw-repro-out-*")
    if err != nil { panic(err) }
    data := &workflow.WorkflowData{
        Name: "expires-repro",
        SafeOutputs: &workflow.SafeOutputsConfig{
            CreateIssues: &workflow.CreateIssuesConfig{Expires: 48},
        },
        ActionResolver: resolver,
    }
    if err := workflow.GenerateMaintenanceWorkflow([]*workflow.WorkflowData{data}, out, version, mode, actionTag, false); err != nil {
        panic(err)
    }
    content, err := os.ReadFile(filepath.Join(out, "agentics-maintenance.yml"))
    if err != nil { panic(err) }
    return string(content)
}

func assertContains(name, yaml, expected string) {
    if !strings.Contains(yaml, expected) {
        re := regexp.MustCompile(`github/gh-aw(?:-actions)?/(?:actions/)?setup-cli@[^\n]+`)
        fmt.Printf("FAIL %s: setup-cli was not SHA-pinned. Found: %q\nExpected: %s\n", name, re.FindAllString(yaml, -1), expected)
        os.Exit(1)
    }
}

func main() {
    root, err := os.MkdirTemp("", "gh-aw-repro-root-*")
    if err != nil { panic(err) }
    cache := workflow.NewActionCache(root)
    cache.Set("github/gh-aw-actions/setup", version, setupSHA)
    cache.Set("github/gh-aw-actions/setup-cli", version, setupCliSHA)
    cache.Set("github/gh-aw/actions/setup", version, setupSHA)
    cache.Set("github/gh-aw/actions/setup-cli", version, setupCliSHA)
    resolver := workflow.NewActionResolver(cache)

    actionYAML := generate(workflow.ActionModeAction, "", resolver)
    assertContains("action mode", actionYAML, "github/gh-aw-actions/setup-cli@"+setupCliSHA+" # "+version)

    releaseYAML := generate(workflow.ActionModeRelease, "", resolver)
    assertContains("release mode", releaseYAML, "github/gh-aw/actions/setup-cli@"+setupCliSHA+" # "+version)

    fallbackYAML := generate(workflow.ActionModeAction, "", nil)
    assertContains("fallback keeps tag without resolver", fallbackYAML, "github/gh-aw-actions/setup-cli@"+version)

    fmt.Println("PASS: setup-cli pinning and fallback edge cases verified")
}
